import { NativeStackScreenProps } from '@react-navigation/native-stack';
import {
  PropsIconsNameCore,
  PropsTokenColorsCore,
} from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import { TextIconType } from '@semparar/design-system-app/src/atomic/molecules/TextIcon/Models';
import { PropsFintechCardRoutes } from '../../../routes/Models';

export interface InvoiceCashbackViewProps {
  handleGoBack: () => void;
  handleContinue?: () => void;
  cashbackInvoiceList?: (pts: number, price: number) => CashbackInvoiceItem[];
  pts?: number;
  price?: number;
  pointsQuantity?: number;
  conversionFactor?: number;
  pointsSelected?: number;
  reaisSelected?: number;
  onConfirmRescue: () => void;
  onExitResult: () => void;
  isRescueLoading?: boolean;
  isRescueConcluded?: boolean;
  isRescueFailed?: boolean;
  showResult?: boolean;
  effectiveShowResult?: boolean;
  items: CashbackInvoiceItem[];
  modalizeRef1: React.RefObject<PropsModalizeRef>;
  onOpenDefault: () => void;
  formattedSelectedPoints: string;
  formattedSelectedReais: string;
  screenTitle?: string;
  height: number;
}

export interface InvoiceCashbackProps extends NativeStackScreenProps<
  PropsFintechCardRoutes,
  'InvoiceCashbackSummary'
> {}

export interface CashbackInvoiceItem {
  text?: string;
  type: TextIconType;
  icon: PropsIconsNameCore;
  iconColor: PropsTokenColorsCore;
  iconColorShape: PropsTokenColorsCore;
  description: string;
}

import React, { useState } from 'react';
import { ActivityIndicator, ScrollView } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Alert,
  Box,
  Button,
  Header,
  Icon,
  ListTextIcon,
  SeparatorHorizontal,
  Text,
} from '@semparar/design-system-app';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';

interface CashbackInvoiceItem {
  type: 'default';
  icon: string;
  iconColor: string;
  iconColorShape: string;
  description: string;
}

function buildHelpItems(
  pointsQuantity: number,
  conversionFactor: number,
): CashbackInvoiceItem[] {
  const convertionValue = new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(pointsQuantity * conversionFactor);

  return [
    {
      type: 'default',
      icon: 'icon-switch-vertical',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: `Cada ${pointsQuantity.toLocaleString('pt-br')} pontos valem ${convertionValue} no cashback`,
    },
    {
      type: 'default',
      icon: 'icon-calendar',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Você define quanto cashback quer aplicar na sua fatura aberta',
    },
    {
      type: 'default',
      icon: 'icon-payment-invoice',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
    },
    {
      type: 'default',
      icon: 'icon-clock',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: 'O cashback acontece em até 72h',
    },
  ];
}

function HelpModal({
  visible,
  onClose,
  items,
}: {
  visible: boolean;
  onClose: () => void;
  items: CashbackInvoiceItem[];
}) {
  if (!visible) return null;

  return (
    <Box
      bgColor="BRAND_COMPLEMENT_03"
      pd="innerLarge"
      style={{
        position: 'absolute',
        bottom: 0,
        left: 0,
        right: 0,
        borderTopLeftRadius: 16,
        borderTopRightRadius: 16,
        shadowColor: '#000',
        shadowOffset: { width: 0, height: -4 },
        shadowOpacity: 0.15,
        shadowRadius: 8,
        elevation: 8,
        zIndex: 10,
      }}
    >
      <Text type="subtitleXXL" mb="smaller" mt="smaller" align="center">
        Use seus pontos para pagar menos na fatura
      </Text>
      <ListTextIcon items={items} ml="nano" mr="nano" type="list" mb="smaller" />
      <Button text="Entendi" onPress={onClose} />
    </Box>
  );
}

function ReviewState({
  formattedSelectedPoints,
  formattedSelectedReais,
  isRescueLoading,
  onConfirmRescue,
}: {
  formattedSelectedPoints: string;
  formattedSelectedReais: string;
  isRescueLoading: boolean;
  onConfirmRescue: () => void;
}) {
  return (
    <>
      <Box ml="smaller" mr="smaller" flex={1} justify="flex-start">
        <Text
          color="INTENSE_COLOR_05"
          testID="invoice-cashback-main-title"
          type="headingMDL"
          mt="smaller"
          mb="small"
        >
          Revise as informações para confirmar o cashback
        </Text>

        <Text
          color="BRAND_COMPLEMENT_01"
          type="paragraphMDM"
          colorBold="BRAND_COMPLEMENT_01"
          mb="nano"
        >
          Valor em pontos
        </Text>
        <Text
          color="BRAND_COMPLEMENT_01"
          type="paragraphL"
          colorBold="BRAND_COMPLEMENT_01"
          mt="nano"
          mb="xxs"
        >
          {formattedSelectedPoints}
        </Text>

        <SeparatorHorizontal
          mb="xxs"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />

        <Text
          color="BRAND_COMPLEMENT_01"
          type="paragraphMDM"
          colorBold="BRAND_COMPLEMENT_01"
          mb="nano"
        >
          Valor em reais
        </Text>
        <Text
          color="BRAND_COMPLEMENT_01"
          type="paragraphL"
          colorBold="BRAND_COMPLEMENT_01"
          mt="nano"
          mb="xxs"
        >
          {formattedSelectedReais}
        </Text>

        <SeparatorHorizontal
          mb="xxs"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />

        <Text
          align="left"
          color="BRAND_COMPLEMENT_01"
          type="paragraphMDM"
          colorBold="BRAND_COMPLEMENT_01"
          mb="nano"
        >
          Cashback em
        </Text>
        <Text
          color="BRAND_COMPLEMENT_01"
          type="paragraphL"
          colorBold="BRAND_COMPLEMENT_01"
          mt="nano"
          mb="xxs"
        >
          Até 72h
        </Text>

        <Alert
          label="O valor é aplicado e exibido nos lançamentos da sua fatura aberta."
          type="highlight"
          icon="icon-calendar"
        />
      </Box>

      <Box ml="smaller" mr="smaller">
        <Button
          text="Confirmar desconto"
          mt="large"
          mb="small"
          onPress={onConfirmRescue}
          disabled={isRescueLoading}
          testID="invoice-cashback-button"
        />
        {isRescueLoading && (
          <Box align="center" mb="small">
            <ActivityIndicator size="large" color="#E10068" />
            <Text type="paragraphMD" mt="nano" color="INTENSE_COLOR_03">
              Aguarde...
            </Text>
          </Box>
        )}
      </Box>
    </>
  );
}

function SuccessState({ onExit }: { onExit: () => void }) {
  return (
    <>
      <Box ml="smaller" mr="smaller" flex={1} justify="center" align="center">
        <Box
          bgColor="PLUS_COLOR_03"
          borderColor="PLUS_COLOR_01"
          borderRadiusBottomLeft="medium"
          pd="innerMedium"
          borderRadiusBottomRight="medium"
          borderRadiusTopRight="medium"
          borderRadiusTopLeft="medium"
          borderBottomWidth="small"
          borderTopWidth="small"
          borderLeftWidth="small"
          borderRightWidth="small"
          mb="small"
        >
          <Icon name="icon-check" color="PLUS_COLOR_01" size="sm" />
        </Box>

        <Text type="subtitleXXL" color="BRAND_COMPLEMENT_01" mb="small">
          Cashback aplicado
        </Text>

        <Text
          align="center"
          type="paragraphLG"
          color="INTENSE_COLOR_03"
          mb="small"
        >
          O valor será aplicado em até 72h na sua fatura aberta.
        </Text>
      </Box>

      <Box ml="smaller" mr="smaller">
        <Button
          text="Ir para o início"
          mt="large"
          mb="small"
          onPress={onExit}
          testID="invoice-cashback-result-success-button"
        />
      </Box>
    </>
  );
}

function ErrorState({ onExit }: { onExit: () => void }) {
  return (
    <>
