}

type ScreenState = 'review' | 'loading' | 'success' | 'error';

function InvoiceCashbackSummaryWrapper({
  pointsSelected = 5000,
  reaisSelected = 50,
  conversionFactor = 0.01,
  pointsQuantity = 100,
  state = 'review' as ScreenState,
}: {
  pointsSelected?: number;
  reaisSelected?: number;
  conversionFactor?: number;
  pointsQuantity?: number;
  state?: ScreenState;
}) {
  const [helpVisible, setHelpVisible] = useState(false);

  const nfPtBR = new Intl.NumberFormat('pt-BR');
  const formattedSelectedPoints = nfPtBR.format(
    Math.max(0, Math.floor(pointsSelected || 0)),
  );
  const formattedSelectedReais = new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  })
    .format(Number.isFinite(reaisSelected) ? reaisSelected : 0)
    .replace(/\s/g, '');

  const isResultState = state === 'success' || state === 'error';
  const screenTitle = isResultState ? 'Conclusão' : 'Cashback na fatura';
  const items = buildHelpItems(pointsQuantity, conversionFactor);

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1} style={{ position: 'relative' }}>
      <Header
        title={screenTitle}
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        isOption={!isResultState}
        iconRight="icon-help"
        onPressIconRight={() => setHelpVisible(true)}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        {state === 'review' && (
          <ReviewState
            formattedSelectedPoints={formattedSelectedPoints}
            formattedSelectedReais={formattedSelectedReais}
            isRescueLoading={false}
            onConfirmRescue={() => {}}
          />
        )}
        {state === 'loading' && (
          <ReviewState
            formattedSelectedPoints={formattedSelectedPoints}
            formattedSelectedReais={formattedSelectedReais}
            isRescueLoading={true}
            onConfirmRescue={() => {}}
          />
        )}
        {state === 'success' && <SuccessState onExit={() => {}} />}
        {state === 'error' && <ErrorState onExit={() => {}} />}
      </ScrollView>

      <HelpModal
        visible={helpVisible}
        onClose={() => setHelpVisible(false)}
        items={items}
      />
    </Box>
  );
}

const meta: Meta<typeof InvoiceCashbackSummaryWrapper> = {
  title: 'Screens/InvoiceCashbackSummary',
  component: InvoiceCashbackSummaryWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    pointsSelected: {
      control: { type: 'number' },
      description: 'Points selected for cashback',
    },
    reaisSelected: {
      control: { type: 'number', step: 0.01 },
      description: 'Reais value selected for cashback',
    },
    state: {
      control: { type: 'select' },
      options: ['review', 'loading', 'success', 'error'],
      description: 'Screen state',
    },
    conversionFactor: {
      control: { type: 'number', step: 0.001 },
      description: 'Points to BRL conversion factor',
    },
    pointsQuantity: {
      control: { type: 'number' },
      description: 'Points quantity for conversion rate label',
    },
  },
};

export default meta;
type Story = StoryObj<typeof InvoiceCashbackSummaryWrapper>;

export const Review: Story = {
  name: 'Review Confirmation',
  args: {
    pointsSelected: 5000,
    reaisSelected: 50,
    conversionFactor: 0.01,
    pointsQuantity: 100,
    state: 'review',
  },
};

export const Loading: Story = {
  name: 'Loading (Confirming)',
  args: {
    pointsSelected: 5000,
    reaisSelected: 50,
    state: 'loading',
  },
};

export const Success: Story = {
  name: 'Success (Cashback Applied)',
  args: {
    pointsSelected: 5000,
    reaisSelected: 50,
    state: 'success',
  },
};

export const Error: Story = {
  name: 'Error (Failed)',
  args: {
    pointsSelected: 5000,
    reaisSelected: 50,
    state: 'error',
  },
};

