import React, { useState } from 'react';
import { ScrollView } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Box,
  Button,
  Header,
  Icon,
  InputBox,
  ListTextIcon,
  Text,
} from '@semparar/design-system-app';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';
import {
  formatCurrencyBR,
  getFormattedPoints,
  getParsedCurrency,
  getParsePoints,
} from '../utils/functions';

interface CashbackInvoiceItem {
  type: 'default';
  icon: string;
  iconColor: string;
  iconColorShape: string;
  description: string;
}

function buildHelpItems(
  pointsQuantity: number,
  conversionFactor: number,
): CashbackInvoiceItem[] {
  const convertionValue = new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(pointsQuantity * conversionFactor);

  return [
    {
      type: 'default',
      icon: 'icon-switch-vertical',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: `Cada ${pointsQuantity.toLocaleString('pt-br')} pontos valem ${convertionValue} no cashback`,
    },
    {
      type: 'default',
      icon: 'icon-calendar',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Você define quanto cashback quer aplicar na sua fatura aberta',
    },
    {
      type: 'default',
      icon: 'icon-payment-invoice',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
    },
    {
      type: 'default',
      icon: 'icon-clock',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: 'O cashback acontece em até 72h',
    },
  ];
}

function HelpModal({
  visible,
  onClose,
  items,
}: {
  visible: boolean;
  onClose: () => void;
  items: CashbackInvoiceItem[];
}) {
  if (!visible) return null;

  return (
    <Box
      bgColor="BRAND_COMPLEMENT_03"
      pd="innerLarge"
      style={{
        position: 'absolute',
        bottom: 0,
        left: 0,
        right: 0,
        borderTopLeftRadius: 16,
        borderTopRightRadius: 16,
        shadowColor: '#000',
        shadowOffset: { width: 0, height: -4 },
        shadowOpacity: 0.15,
        shadowRadius: 8,
        elevation: 8,
        zIndex: 10,
      }}
    >
      <Text type="subtitleXXL" mb="smaller" mt="smaller" align="center">
        Use seus pontos para pagar menos na fatura
      </Text>
      <ListTextIcon items={items} ml="nano" mr="nano" type="list" mb="smaller" />
      <Button text="Entendi" onPress={onClose} />
    </Box>
  );
}

function InvoiceCashbackPointsWrapper({
  points = 15320,
  conversionFactor = 0.01,
  pointsQuantity = 100,
  showHelp = false,
  initialPointsValue = '',
  initialReaisValue = '',
  forcePointsError = false,
  forceReaisError = false,
}: {
  points?: number;
  conversionFactor?: number;
  pointsQuantity?: number;
  showHelp?: boolean;
  initialPointsValue?: string;
  initialReaisValue?: string;
  forcePointsError?: boolean;
  forceReaisError?: boolean;
}) {
  const [pointsValue, setPointsValue] = useState(initialPointsValue);
  const [reaisValue, setReaisValue] = useState(initialReaisValue);
  const [pointsError, setPointsError] = useState(forcePointsError);
  const [reaisError, setReaisError] = useState(forceReaisError);
  const [helpVisible, setHelpVisible] = useState(showHelp);

  const rate = conversionFactor > 0 ? conversionFactor : 0;
  const finalPrice = Number((Math.trunc(points) * conversionFactor).toFixed(2));
  const formattedPrice = formatCurrencyBR(finalPrice);
  const convertionValue = formatCurrencyBR(pointsQuantity * conversionFactor);

  const handleChangePoints = (text: string) => {
    const val = getParsePoints(text);
    const formatted = val ? getFormattedPoints(val) : '';
    setPointsValue(formatted);

    if (rate > 0) {
      setReaisValue(val > 0 ? formatCurrencyBR(val * rate) : '');
    }
    setPointsError(val > Math.trunc(points));
  };

  const handleChangeReais = (text: string) => {
    const val = getParsedCurrency(text);
    const formatted = val > 0 ? formatCurrencyBR(val) : '';
    setReaisValue(formatted);

    if (rate > 0) {
      const ptsFromReais = Math.round(val / rate);
      setPointsValue(ptsFromReais > 0 ? getFormattedPoints(ptsFromReais) : '');
    }
    setReaisError(val > finalPrice);
  };

  const handleUseAll = () => {
    setPointsValue(getFormattedPoints(points));
    setReaisValue(formatCurrencyBR(finalPrice));
    setPointsError(false);
    setReaisError(false);
  };

  const isDisabled =
    pointsValue === '' ||
    reaisValue === '' ||
    pointsValue === '0' ||
    reaisValue === '0' ||
    pointsError ||
    reaisError;

  const items = buildHelpItems(pointsQuantity, conversionFactor);

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1} style={{ position: 'relative' }}>
      <Header
        title="Cashback na fatura"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        isOption
        iconRight="icon-help"
        onPressIconRight={() => setHelpVisible(true)}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        <Box ml="smaller" mr="smaller" flex={1} justify="flex-start">
          <Text
            color="INTENSE_COLOR_05"
            testID="invoice-cashback-main-title"
            type="headingMDL"
            mt="smaller"
          >
            Defina quanto cashback quer na sua fatura
          </Text>

          <Box direction mb="smaller" mt="nano" align="center">
            <Text type="paragraphMD" mr="quark">
              Pontos disponíveis:
            </Text>
            <Text type="paragraphXXXL" mr="quark">
              {getFormattedPoints(points)}
            </Text>
            <Text type="paragraphMD">({formattedPrice})</Text>
          </Box>

          <InputBox
            label="Valor em pontos"
            placeholder="0"
            showLabel
            keyboardType="number-pad"
            value={pointsValue}
            onChangeText={handleChangePoints}
            error={pointsError}
            textError="Você precisa informar um valor menor."
            textRight="Usar todos"
            onPressTextRight={handleUseAll}
          />

          <Box direction mb="xxs" mt="xxs" align="center">
            <Box height="1px" bgColor="INTENSE_COLOR_02" width="45%" />
            <Icon
              name="icon-switch-vertical"
              size="xxs"
              color="INTENSE_COLOR_03"
              mr="nano"
              ml="nano"
            />
            <Box height="1px" bgColor="INTENSE_COLOR_02" width="45%" />
          </Box>

          <InputBox
            label="Valor em reais"
            placeholder="R$0,00"
            showLabel
            keyboardType="decimal-pad"
            value={reaisValue}
            onChangeText={handleChangeReais}
            error={reaisError}
            textError="Você precisa informar um valor menor."
          />

          <Box direction mb="xxs" mt="xxs" align="center">
            <Text type="paragraphMD">
              Cada {pointsQuantity || '0'} pontos valem{' '}
              {convertionValue || formatCurrencyBR(0)} de cashback na fatura.
            </Text>
